def build_lookup() -> dict:
    base = datetime(2026, 5, 31, 0, 0, tzinfo=timezone.utc)
    lookup = {}
    for i, (ws, wd) in enumerate(zip(_OM_WS, _OM_WD)):
        ts = (base + timedelta(hours=i)).strftime("%Y-%m-%dT%H:%M:%SZ")
        lookup[ts] = (round(ws, 2), int(wd % 360))
    return lookup


def main():
    with open(FIXTURE, encoding="utf-8") as f:
        fixture = json.load(f)

    lookup = build_lookup()
    new_ws, new_wd, matched, missing_ts = [], [], 0, []

    for ts in fixture["timestamps"]:
        if ts in lookup:
            ws, wd = lookup[ts]
            new_ws.append(ws)
            new_wd.append(wd)
            matched += 1
        else:
            new_ws.append(None)
            new_wd.append(None)
            missing_ts.append(ts)

    if missing_ts:
        print(f"WARNING: {len(missing_ts)} timestamps had no Open-Meteo match:")
        for t in missing_ts[:5]:
            print(f"  {t}")

    fixture["ws"] = new_ws
    fixture["wd"] = new_wd
    fixture["meta"]["wind_note"] = (
        "Real wind data from Open-Meteo ERA5 reanalysis (10 m, m/s, degrees). "
        "Source: archive-api.open-meteo.com, lat=42.80686, lon=-1.64405, 2026-05-31 to 2026-06-28 UTC."
    )
    fixture["meta"]["wind_source"] = "open-meteo-era5"

    with open(FIXTURE, "w", encoding="utf-8") as f:
        json.dump(fixture, f, indent=2, ensure_ascii=False)

    print(f"Done. {matched}/{len(fixture['timestamps'])} timestamps matched.")
    print(f"ws range: {min(w for w in new_ws if w is not None):.2f} – {max(w for w in new_ws if w is not None):.2f} m/s")
    print(f"Fixture written: {FIXTURE}")

    # Also update the server CSV fixture if it exists
    if SERVER_FIXTURE.exists():
        import csv
        rows = []
        with open(SERVER_FIXTURE, newline="", encoding="utf-8") as f:
            reader = csv.DictReader(f)
            fieldnames = reader.fieldnames
            for row in reader:
                ts = row.get("date") or row.get("timestamp") or ""
                if ts in lookup:
                    ws, wd = lookup[ts]
                    row["ws"] = ws
                    row["wd"] = wd
                rows.append(row)
        with open(SERVER_FIXTURE, "w", newline="", encoding="utf-8") as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(rows)
        print(f"Server CSV fixture updated: {SERVER_FIXTURE}")


if __name__ == "__main__":
    main()
